  import sailpoint.api.IdentityService;
  import sailpoint.object.Application;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  
  //log.error("Entering: Rule-ASCN-Global-IdentityAttribute-samAccountName");

  //Identity identity = context.getObjectByName(Identity.class, "10173844");

  private List getADAppsForNetworkLogonID(List adAppNames) {

    List adApps = new ArrayList();

    for (String appName : adAppNames) {

      Application app = context.getObjectByName(Application.class, appName);

      if (app != null) {

        adApps.add(app);

      }

    }

    return adApps;

  }

  String samAccountName = null;

  IdentityService idService = new IdentityService(context);

  List adApps = getADAppsForNetworkLogonID(Util.csvToList("AD-DS,AD-WIAPP,AD-WIGLE,AD-KSWIC,AD-OKTUL,AD-MIROC,AD-AHMFM,AD-ACMHO,AD-AHSCN,AD-AMITA"));

  if (identity != null && idService != null) {

    for (Application app : adApps) {

      List adLinks = idService.getLinks(identity, app);

      if (adLinks != null) {

        for (Link link : adLinks) {

          if (Util.isNotNullOrEmpty(link.getAttribute("sAMAccountName")) && !link.getAttribute("sAMAccountName").endsWith("ongoogle") && !Util.nullSafeCaseInsensitiveEq(link.getAttribute("psAccount"), "true")) {

            return link.getAttribute("sAMAccountName");

          }

        }

      }

    }

  }

  //log.error("Exiting: Rule-ASCN-Global-IdentityAttribute-samAccountName");
  //log.error("sAMAccountName: " + samAccountName);

  return samAccountName;
